impl Polygon {
    pub fn to_wkt(&self) -&gt; String {
        let coords: Vec&lt;String&gt; = self.exterior
            .iter()
            .map(|p| format!("{} {}", p.x, p.y)) // "x y"
            .collect();

        // Unimos con comas
        let coords_str = coords.join(", ");

        format!("POLYGON(({}))", coords_str)
    }
